  ('optometrist-moex-02514', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關塑膠鏡架鏡腳張幅的敘述，下列何者錯誤？', '["鏡腳張幅是指開展鏡腳與前框形成的夾角", "鏡腳張幅稍微大於直角是正常的", "將端片加熱後且向內彎曲可減少鏡腳張幅", "將前框隱藏式絞鏈插入至較深的塑膠中可增加鏡腳張幅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
